use std::io;

async fn read_and_parse(path: &str) -> Result<Vec<i32>, Box<dyn std::error::Error>> {
    let content = tokio::fs::read_to_string(path).await?;
    let numbers: Vec<i32> = content
        .lines()
        .map(|line| line.trim().parse::<i32>())
        .collect::<Result<_, _>>()?;
    Ok(numbers)
}

#[tokio::main]
async fn main() {
    let handle = tokio::spawn(async {
        // This could fail
        might_fail().await
    });

    match handle.await {
        Ok(Ok(value)) => println!("Success: {}", value),
        Ok(Err(e)) => println!("Task returned error: {}", e),
        Err(join_err) => println!("Task panicked: {}", join_err),
    }
}

async fn might_fail() -> Result<String, String> {
    Err("something went wrong".to_string())
}

use tokio::try_join;

async fn fetch_user() -> Result<String, String> {
    Ok("Alice".to_string())
}

async fn fetch_permissions() -> Result<Vec<String>, String> {
    Ok(vec!["read".to_string(), "write".to_string()])
}

#[tokio::main]
async fn main() -> Result<(), String> {
    // If either fails, try_join! returns the first error immediately
    let (user, perms) = try_join!(fetch_user(), fetch_permissions())?;
    println!("User: {}, Permissions: {:?}", user, perms);
    Ok(())
}

use tokio::time::{timeout, Duration};

async fn slow_operation() -> String {
    tokio::time::sleep(Duration::from_secs(10)).await;
    "done".to_string()
}

#[tokio::main]
async fn main() {
    match timeout(Duration::from_secs(2), slow_operation()).await {
        Ok(result) => println!("Got: {}", result),
        Err(_) => println!("Operation timed out!"),
    }
}
